+/**
+ * Supervisor Service - Daemon process management.
+ *
+ * Provides:
+ * - Start/stop/restart for allowlisted daemons
+ * - Health checks with automatic restart
+ * - Log streaming and collection
+ * - WebSocket events for status changes
+ */
+
+import { type Subprocess } from "bun";
+import { getCorrelationId, getLogger } from "../middleware/correlation";
+import type { Channel } from "../ws/channels";
+import { getHub } from "../ws/hub";
+import { logger } from "./logger";
+
+// ============================================================================
+// Types
+// ============================================================================
+
+export type RestartPolicy = "always" | "on-failure" | "never";
+
+export type DaemonStatus = "starting" | "running" | "stopping" | "stopped" | "failed";
+
+export interface DaemonSpec {
+  name: string;
+  command: string[];
+  port?: number;
+  healthEndpoint?: string;
+  restartPolicy: RestartPolicy;
+  maxRestarts: number;
+  restartDelayMs: number;
+  env?: Record<string, string>;
+}
+
+export interface DaemonState {
+  name: string;
+  status: DaemonStatus;
+  pid?: number;
+  port?: number;
+  startedAt?: Date;
+  stoppedAt?: Date;
+  restartCount: number;
+  lastHealthCheck?: Date;
+  lastError?: string;
+  uptime?: number;
+}
+
+export interface DaemonLogEntry {
+  timestamp: Date;
+  level: "stdout" | "stderr";
+  message: string;
+}
+
+export interface SupervisorEvent {
+  type: "daemon.started" | "daemon.stopped" | "daemon.failed" | "daemon.health_changed" | "daemon.restarting";
+  data: {
+    name: string;
+    status: DaemonStatus;
+    pid?: number;
+    port?: number;
+    error?: string;
+    restartCount?: number;
+  };
+}
+
+// ============================================================================
+// Default Daemon Specifications
+// ============================================================================
+
+const DEFAULT_SPECS: DaemonSpec[] = [
+  {
+    name: "agent-mail",
+    command: ["mcp-agent-mail", "serve"],
+    port: 8765,
+    healthEndpoint: "/health",
+    restartPolicy: "always",
+    maxRestarts: 5,
+    restartDelayMs: 1000,
+  },
+  {
+    name: "cm-server",
+    command: ["cm", "serve"],
+    port: 8766,
+    healthEndpoint: "/health",
+    restartPolicy: "always",
+    maxRestarts: 5,
+    restartDelayMs: 1000,
+  },
+  {
+    name: "bd-daemon",
+    command: ["bd", "daemon"],
+    restartPolicy: "on-failure",
+    maxRestarts: 3,
+    restartDelayMs: 2000,
+  },
+];
+
+// ============================================================================
+// Supervisor Service Class
+// ============================================================================
+
+export class SupervisorService {
+  private daemons = new Map<string, DaemonState>();
+  private processes = new Map<string, Subprocess>();
+  private specs = new Map<string, DaemonSpec>();
+  private logs = new Map<string, DaemonLogEntry[]>();
+  private healthCheckIntervals = new Map<string, ReturnType<typeof setInterval>>();
+  private started = false;
+
+  private static readonly MAX_LOG_ENTRIES = 1000;
+  private static readonly HEALTH_CHECK_INTERVAL = 5000;
+
+  constructor(specs: DaemonSpec[] = DEFAULT_SPECS) {
