+      log.error({ correlationId, daemon: name, restartCount: state.restartCount }, "Daemon max restarts exceeded");
+      this.emitEvent("daemon.failed", state);
+    } else {
+      state.status = "stopped";
+      this.emitEvent("daemon.stopped", state);
+    }
+  }
