+  private collectLogs(name: string, proc: Subprocess): void {
+    const logs = this.logs.get(name) ?? [];
+
+    // Read stdout
+    if (proc.stdout) {
+      this.readStream(proc.stdout, (line) => {
+        this.addLog(logs, "stdout", line);
+      });
+    }
+
+    // Read stderr
+    if (proc.stderr) {
+      this.readStream(proc.stderr, (line) => {
+        this.addLog(logs, "stderr", line);
+      });
+    }
+  }
+
+  private async readStream(
+    stream: ReadableStream<Uint8Array>,
+    callback: (line: string) => void,
+  ): Promise<void> {
+    const reader = stream.getReader();
+    const decoder = new TextDecoder();
+    let buffer = "";
+
+    try {
+      while (true) {
+        const { done, value } = await reader.read();
+        if (done) break;
+
+        buffer += decoder.decode(value, { stream: true });
+
+        // Process complete lines
+        const lines = buffer.split("\n");
+        buffer = lines.pop() ?? "";
+
+        for (const line of lines) {
+          if (line.trim()) {
+            callback(this.redactSecrets(line));
+          }
+        }
+      }
+
+      // Process remaining buffer
+      if (buffer.trim()) {
+        callback(this.redactSecrets(buffer));
+      }
+    } catch {
+      // Stream closed
+    }
+  }
+
+  private addLog(logs: DaemonLogEntry[], level: "stdout" | "stderr", message: string): void {
+    logs.push({
+      timestamp: new Date(),
+      level,
+      message,
+    });
+
+    // Trim logs to max size
+    if (logs.length > SupervisorService.MAX_LOG_ENTRIES) {
+      logs.splice(0, logs.length - SupervisorService.MAX_LOG_ENTRIES);
+    }
+  }
+
+  private redactSecrets(message: string): string {
+    // Redact common secret patterns
+    return message
+      .replace(/(?:api[_-]?key|token|password|secret|auth)[=:]\s*["']?[^\s"']+["']?/gi, "[REDACTED]")
+      .replace(/sk-[a-zA-Z0-9]{20,}/g, "sk-[REDACTED]")
+      .replace(/Bearer\s+[a-zA-Z0-9._-]+/gi, "Bearer [REDACTED]");
+  }
+
+  private emitEvent(type: SupervisorEvent["type"], state: DaemonState): void {
+    const event: SupervisorEvent = {
+      type,
+      data: {
+        name: state.name,
+        status: state.status,
+        pid: state.pid,
+        port: state.port,
+        error: state.lastError,
+        restartCount: state.restartCount,
+      },
+    };
